#!/usr/bin/env python3
import argparse
import sys


def count_file(filepath):
    try:
        with open(filepath, "r") as f:
            content = f.read()
            lines = content.count("\n")
            words = len(content.split())
            chars = len(content)
            return {"lines": lines, "words": words, "chars": chars}
    except FileNotFoundError:
        return None
    except Exception as e:
        return None


def main():
    parser = argparse.ArgumentParser(
        description="Print newline, word, and character counts for each FILE."
    )
    parser.add_argument("files", nargs="+", metavar="FILE", help="File(s) to process")
    parser.add_argument(
        "-l", "--lines", action="store_true", help="print the newline counts"
    )
    parser.add_argument(
        "-w", "--words", action="store_true", help="print the word counts"
    )
    parser.add_argument(
        "-c", "--chars", action="store_true", help="print the character counts"
    )

    args = parser.parse_args()

    show_lines = args.lines
    show_words = args.words
    show_chars = args.chars

    if not (show_lines or show_words or show_chars):
        show_lines = show_words = show_chars = True

    total_lines = 0
    total_words = 0
    total_chars = 0
    has_error = False

    results = []

    for filepath in args.files:
        counts = count_file(filepath)
        if counts is None:
            print(
                f"wordcount.py: {filepath}: No such file or directory", file=sys.stderr
            )
            has_error = True
            continue

        total_lines += counts["lines"]
        total_words += counts["words"]
        total_chars += counts["chars"]

        parts = []
        if show_lines:
            parts.append(str(counts["lines"]))
        if show_words:
            parts.append(str(counts["words"]))
        if show_chars:
            parts.append(str(counts["chars"]))
        parts.append(filepath)

        results.append("\t".join(parts))

    for result in results:
        print(result)

    if len(args.files) > 1 and not has_error:
        parts = []
        if show_lines:
            parts.append(str(total_lines))
        if show_words:
            parts.append(str(total_words))
        if show_chars:
            parts.append(str(total_chars))
        parts.append("total")
        print("\t".join(parts))

    sys.exit(1 if has_error else 0)


if __name__ == "__main__":
    main()
